import { streamText } from 'ai';
import { createStreamableValue } from 'ai/rsc';

const detectTokenWaste = async (messages: any[]) => {
  let totalTokens = 0;
  let callCount = 0;

  const result = await streamText({
    model: openai('gpt-4o-mini'),
    messages,
    onFinish: ({ usage }) => {
      totalTokens += usage.total || 0;
      callCount++;
      if (totalTokens > 5000) {
        console.warn(`⚠️ High token usage: ${totalTokens} tokens over ${callCount} calls`);
      }
    },
  });

  return result;
};

import { generateObject } from 'ai';

const trackToolCalls = async (tools: any[]) => {
  const callCache = new Map();

  const result = await generateObject({
    model: openai('gpt-4o'),
    tools,
    toolChoice: 'auto',
    onToolCall: ({ toolCall }) => {
      const key = `${toolCall.name}:${JSON.stringify(toolCall.args)}`;
      if (callCache.has(key)) {
        console.error(`🔄 Duplicate tool call detected: ${key}`);
      }
      callCache.set(key, Date.now());
    },
  });

  return result;
};

import { generateText } from 'ai';

const analyzePromptCost = async (messages: any[]) => {
  const systemTokenEstimate = messages
    .filter(m => m.role === 'system')
    .reduce((sum, msg) => sum + (msg.content?.length || 0) / 4, 0);

  if (systemTokenEstimate > 1500) {
    console.warn(`📈 Oversized system prompt: ~${systemTokenEstimate} tokens`);
  }

  const { text } = await generateText({ model: openai('gpt-4o-mini'), messages });
  return text;
};

