import { generateObject } from 'ai';

const memoizedAgent = async (messages: any[]) => {
  const toolCache = new Map();

  const result = await generateObject({
    model: openai('gpt-4o'),
    messages,
    tools: {
      fetchWeather: {
        description: 'Get weather',
        parameters: z.object({ location: z.string() }),
        execute: async ({ location }) => {
          const cacheKey = `weather:${location}`;
          if (toolCache.has(cacheKey)) {
            return toolCache.get(cacheKey);
          }
          const result = await getWeather(location);
          toolCache.set(cacheKey, result);
          return result;
        },
      },
    },
  });

  return result;
};

const trimSystemPrompt = (messages: any[], maxTokens = 800) => {
  const systemMsgs = messages.filter(m => m.role === 'system');
  let totalTokens = 0;

  // Keep only essential instructions for long conversations
  const trimmed = messages.map(msg => {
    if (msg.role === 'system' && totalTokens > maxTokens) {
      return { ...msg, content: msg.content.slice(0, maxTokens * 4) };
    }
    totalTokens += (msg.content?.length || 0) / 4;
    return msg;
  });

  return trimmed;
};

import { generateText } from 'ai';
