import { createMiddleware } from '@vex_dev/sdk/ai';
import { generateText, streamText } from 'ai';

// Initialize Vex middleware - 3 lines total
initVex({
  projectId: process.env.VEX_PROJECT_ID!,
  token: process.env.VEX_TOKEN!,
});

const instrumentedGenerateText = createMiddleware({
  name: 'agent-generate',
  detect: ['token_spikes', 'tool_looping', 'prompt_bloat'],
  autoFix: ['early_termination', 'tool_cache'],
})(generateText);

const instrumentedStreamText = createMiddleware({
  name: 'agent-stream',
  maxTokens: 2500,
  budgetAlert: 0.75, // alert at 75% budget
})(streamText);

// Usage unchanged
export async function generateAgentResponse(messages: any[]) {
  return await instrumentedGenerateText({
    model: openai('gpt-4o-mini'),
    messages,
  });
}
